using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Chat client ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient();

// --- Tools ---
var notebook = new Notebook();
var webSearch = new WebSearchTool();

IList<AITool> tools =
[
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.ReadNotes),
];

// --- Conversation ---
List<ChatMessage> history =
[
    new(ChatRole.System, """
        You are a thorough research agent. Given a topic you must:
        1. Search the web with varied queries to gather broad information.
        2. Fetch the most promising pages to read details.
        3. Save key findings as notes (aim for 5-10 notes).
        4. When you have enough material, read your notes and produce a
           well-structured summary with sections, key facts, and sources.
        Always cite URLs where possible.
        """),
];

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

history.Add(new(ChatRole.User,
    $"Research the following topic and provide a comprehensive summary:\n\n{topic}"));

// --- Agent loop ---
Console.WriteLine($"\n📚 Researching: {topic}\n");

var options = new ChatOptions { Tools = tools };
const int maxIterations = 25;

for (int i = 0; i < maxIterations; i++)
{
    var response = await chatClient.GetResponseAsync(history, options);

    // Append every response message to history
    foreach (var msg in response.Messages)
        history.Add(msg);

    // Gather any tool calls from the response
    var calls = response.Messages
        .SelectMany(m => m.Contents.OfType<FunctionCallContent>())
        .ToList();

    if (calls.Count == 0)
    {
        // No tool calls → final answer
        var answer = response.Messages
            .Select(m => m.Text)
            .FirstOrDefault(t => !string.IsNullOrWhiteSpace(t));
        Console.WriteLine(answer ?? "(No response from model)");
        break;
    }

    // Invoke each requested tool
    foreach (var call in calls)
    {
        var argSummary = call.Arguments is { Count: > 0 }
            ? string.Join(", ", call.Arguments.Select(
                kv => $"{kv.Key}={Truncate(kv.Value?.ToString(), 80)}"))
            : "";
        Console.WriteLine($"  🔧 {call.Name}({argSummary})");

        var fn = tools.OfType<AIFunction>().FirstOrDefault(f =>
            f.Name.Equals(call.Name, StringComparison.OrdinalIgnoreCase));

        object? result;
        if (fn is not null)
        {
            try { result = await fn.InvokeAsync(call.Arguments); }
            catch (Exception ex) { result = $"Tool error: {ex.Message}"; }
        }
        else
        {
            result = $"Unknown tool '{call.Name}'.";
        }

        history.Add(new ChatMessage(ChatRole.Tool,
            [new FunctionResultContent(call.CallId, call.Name, result)]));
    }

    Console.WriteLine();
}

Console.WriteLine("\n✅ Research complete.");

// --- Helpers ---------------------------------------------------------------

static string Truncate(string? value, int max) =>
    value is null ? ""
    : value.Length <= max ? value
    : string.Concat(value.AsSpan(0, max), "…");

// ===========================================================================
//  Tool: Web Search (DuckDuckGo HTML, no API key needed)
// ===========================================================================

sealed partial class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(20),
    };

    [Description("Search the web for a query. Returns titles, snippets, and URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={WebUtility.UrlEncode(query)}";
            var html = await Http.GetStringAsync(url);

            var titles = TitleRegex().Matches(html)
                .Select(m => StripHtml(m.Groups["v"].Value).Trim()).ToList();
            var snippets = SnippetRegex().Matches(html)
                .Select(m => StripHtml(m.Groups["v"].Value).Trim()).ToList();
            var urls = UrlRegex().Matches(html)
                .Select(m => CleanUrl(m.Groups["v"].Value)).ToList();

            if (titles.Count == 0)
                return $"No results found for '{query}'. Try different keywords.";

            var sb = new StringBuilder($"Search results for '{query}':\n");
            for (int i = 0; i < Math.Min(titles.Count, 8); i++)
            {
                sb.AppendLine($"\n{i + 1}. {titles[i]}");
                if (i < snippets.Count && snippets[i].Length > 0)
                    sb.AppendLine($"   {snippets[i]}");
                if (i < urls.Count && urls[i].Length > 0)
                    sb.AppendLine($"   URL: {urls[i]}");
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch and extract the text content of a web page.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL to fetch")] string url)
    {
        try
        {
            if (!url.StartsWith("http://") && !url.StartsWith("https://"))
                url = "https://" + url;

            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);
            text = CollapseWhitespace().Replace(text, " ").Trim();

            const int maxLen = 5000;
            if (text.Length > maxLen)
                text = string.Concat(text.AsSpan(0, maxLen), "… [truncated]");

            return string.IsNullOrWhiteSpace(text)
                ? "Page returned no readable text content."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    // --- Private helpers ---

    private static string StripHtml(string html)
    {
        html = ScriptStyleRegex().Replace(html, "");
        html = TagRegex().Replace(html, " ");
        return WebUtility.HtmlDecode(html);
    }

    private static string CleanUrl(string raw)
    {
        var match = UddgRegex().Match(raw);
        return match.Success ? WebUtility.UrlDecode(match.Groups[1].Value) : raw;
    }

    // Source-generated regexes for performance
    [GeneratedRegex(@"class=""result__a""[^>]*>(?<v>.*?)</a>", RegexOptions.Singleline)]
    private static partial Regex TitleRegex();

    [GeneratedRegex(@"class=""result__snippet""[^>]*>(?<v>.*?)</a>", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex(@"class=""result__a""[^>]*href=""(?<v>[^""]+)""")]
    private static partial Regex UrlRegex();

    [GeneratedRegex(@"uddg=([^&]+)")]
    private static partial Regex UddgRegex();

    [GeneratedRegex(@"<(script|style)[^>]*>.*?</\1>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex CollapseWhitespace();
}

// ===========================================================================
//  Tool: Notebook (in-memory note storage)
// ===========================================================================

sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Save a research note. Use this to record each key finding.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The note content")] string content)
    {
        _notes.Add((title, content));
        return $"✅ Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Read all saved research notes.")]
    public string ReadNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"\n--- Note #{i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
        }
        return sb.ToString();
    }
}

